  SharpDX.Vector2 pointB = new SharpDX.Vector2(300, 300);  

  // Draw the line using the Stroke SharpDX brush  
  RenderTarget.DrawLine(pointA, pointB, MyStroke.BrushDX, MyStroke.Width, MyStroke.StrokeStyle);  

